INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-38b282f1bb6bcace', 'upcoming-support-961418675ce996d6', 'labSteps', 'Lab steps', 0, 'text', 'Hydrogen: hydrochloric acid + magnesium ribbon, then test with a burning splint.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-4df06218134fce62', 'upcoming-support-961418675ce996d6', 'labSteps', 'Lab steps', 1, 'text', 'Oxygen: hydrogen peroxide + potassium iodide, then test with a glowing splint.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-e49b7d47ba295c71', 'upcoming-support-961418675ce996d6', 'labSteps', 'Lab steps', 2, 'text', 'Carbon dioxide: vinegar + baking soda, then test with a burning splint and, if needed, a glowing splint.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-0b1ed1468c27d9af', 'upcoming-support-961418675ce996d6', 'propertyUseLinks', 'Property to use ideas', 0, 'text', 'Hydrogen is flammable, so it can be used as a fuel source such as rocket fuel or other energy applications.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-daa9da9583a21c1c', 'upcoming-support-961418675ce996d6', 'propertyUseLinks', 'Property to use ideas', 1, 'text', 'Oxygen supports combustion, so it is useful for medical breathing support and processes that need burning.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-3ec1419ff5c2d8e1', 'upcoming-support-961418675ce996d6', 'propertyUseLinks', 'Property to use ideas', 2, 'text', 'Carbon dioxide does not support combustion, so it is used in fire extinguishers.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-4f9bd9c24bd08797', 'upcoming-support-961418675ce996d6', 'teacherQuestions', 'Teacher questions', 0, 'text', 'How are the physical properties of the gases similar?', NULL, NULL);
