INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-a8b727deea946623', 'upcoming-support-961418675ce996d6', 'teacherQuestions', 'Teacher questions', 2, 'text', 'How are the chemical properties different?', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-a0b80c42010ad924', 'upcoming-support-961418675ce996d6', 'teacherQuestions', 'Teacher questions', 3, 'text', 'Which gas is used in fire extinguishers and why?', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-9ff3b7308dd87b03', 'upcoming-support-961418675ce996d6', 'teacherQuestions', 'Teacher questions', 4, 'text', 'Which gas was used in balloons and why is it no longer commonly used?', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-769a5b6ec54ed69a', 'upcoming-support-961418675ce996d6', 'teacherQuestions', 'Teacher questions', 5, 'text', 'Which gas is used to help hospital patients breathe?', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-8cce761750cbc498', 'upcoming-support-961418675ce996d6', 'teacherQuestions', 'Teacher questions', 6, 'text', 'Pick one property and explain why it makes that substance useful in real life.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-abf8eb2699815546', 'upcoming-support-961418675ce996d6', 'teacherQuestions', 'Teacher questions', 7, 'text', 'Explain why a material''s physical property can make it a good choice for a job, like carbon in pencil lead.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-e478cb5d0996241a', 'upcoming-support-961418675ce996d6', 'flexibleThinkingExamples', 'Flexible thinking', 0, 'text', 'Non-metal carbon in pencil lead is soft enough to rub onto paper, so that physical property makes it useful for writing.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-6f01c28710bf377f', 'upcoming-support-961418675ce996d6', 'flexibleThinkingExamples', 'Flexible thinking', 1, 'text', 'A teacher may ask for a property-to-use explanation, not just the name of the gas or substance.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-a4ffd62978b6907d', 'upcoming-support-961418675ce996d6', 'flexibleThinkingExamples', 'Flexible thinking', 2, 'text', 'Practice answering in this format: property -> what it means -> why that helps in the real-world use.', NULL, NULL);
INSERT INTO subject_topic_cards (id, subject_slug, title, summary, source_kind, source_upload_id, source_ref, created_at, updated_at) VALUES ('subject-card-fd50ab2928f76c05', 'science', 'Atomic Models (Billiard Ball → Bohr-Rutherford)', 'Scientists changed how they thought about atoms after new experiments. Each model tried to explain what atoms look like and how parts (like electrons and nucleus) are arranged. Evidence from experiments made the models better over time.', 'manual', 'upload-ddb9dd7d6b929db3', NULL, '2026-03-29T15:04:28.951Z', '2026-03-29T15:04:28.951Z');
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-dd991c16be13f67f', 'subject-card-fd50ab2928f76c05', 'keyConcepts', 'Key concepts', 0, 'text', 'Billiard Ball (Dalton): Atoms are tiny, solid, indivisible spheres. No internal parts.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-4ddf8accd6824ac6', 'subject-card-fd50ab2928f76c05', 'keyConcepts', 'Key concepts', 1, 'text', 'Plum Pudding (Thomson): Atoms have electrons inside a positive “pudding” spread out.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-f013de964ddbbb8d', 'subject-card-fd50ab2928f76c05', 'keyConcepts', 'Key concepts', 2, 'text', 'Revised Nuclear (Rutherford): Most mass and positive charge are in a small nucleus; electrons are around it. Discovered from gold-foil experiment.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-c18acce8404dd3e5', 'subject-card-fd50ab2928f76c05', 'keyConcepts', 'Key concepts', 3, 'text', 'Planetary / Bohr-Rutherford: Electrons move in set orbits with certain energies. Explains simple atomic spectra.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-a0abadca18a4da43', 'subject-card-fd50ab2928f76c05', 'teacherNotes', 'Teacher notes summary', 0, 'text', 'Key question: What experiment or observation showed each model needed to change?', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-951df414bda6774d', 'subject-card-fd50ab2928f76c05', 'teacherNotes', 'Teacher notes summary', 1, 'text', 'Gold-foil experiment: most alpha particles passed through but some bounced back → small dense nucleus.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-53f1c8a5a427505c', 'subject-card-fd50ab2928f76c05', 'teacherNotes', 'Teacher notes summary', 2, 'text', 'Thomson’s cathode ray work found electrons, so atoms were not indivisible.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-4ee83c3c425cf284', 'subject-card-fd50ab2928f76c05', 'teacherNotes', 'Teacher notes summary', 3, 'text', 'Bohr used hydrogen light lines to suggest fixed electron energy levels.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-73fb232199e3385d', 'subject-card-fd50ab2928f76c05', 'resources', 'Useful learning resources', 0, 'resource', NULL, '10.2 Atomic Model Summary.pdf', '../uploads/docs/10-2-Atomic-Model-Summary-2026-03-29T14-07-23-845Z.pdf');
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-46b15b71bc8660fa', 'subject-card-fd50ab2928f76c05', 'resources', 'Useful learning resources', 1, 'resource', NULL, 'Use the PDF teacher handout as your main note. Copy the table headings: Model, Key Points, Limitations, Evidence for Change.', NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-3619af4e1ade4efa', 'subject-card-fd50ab2928f76c05', 'resources', 'Useful learning resources', 2, 'resource', NULL, 'Bring class textbook pages on atomic theory if you have them. Review notes on Thomson, Rutherford, and Bohr before class.', NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-04e151aa82d1996d', 'subject-card-fd50ab2928f76c05', 'quizEasy', 'Easy quiz questions', 0, 'text', 'List the four models in order and write one key point for each (1 sentence each).', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-e44742d5de01e178', 'subject-card-fd50ab2928f76c05', 'quizEasy', 'Easy quiz questions', 1, 'text', 'Draw the plum-pudding and nuclear models (simple sketch).', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-5e282a16b4255f2a', 'subject-card-fd50ab2928f76c05', 'quizMedium', 'Medium quiz questions', 0, 'text', 'Explain in 2–3 sentences how the gold-foil experiment changed the plum-pudding model.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-ac03d02880f96e2b', 'subject-card-fd50ab2928f76c05', 'quizMedium', 'Medium quiz questions', 1, 'text', 'Write one short paragraph comparing Bohr’s orbits to the idea of electrons in the revised nuclear model.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-5fabba55e69bea8d', 'subject-card-fd50ab2928f76c05', 'quizHard', 'Hard quiz questions', 0, 'text', 'Describe how Bohr’s model explains hydrogen’s spectral lines and why it doesn’t fully work for bigger atoms.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-6d26cb680bd2883e', 'subject-card-fd50ab2928f76c05', 'quizHard', 'Hard quiz questions', 1, 'text', 'Given a short description of an experiment result, pick which atomic model it supports and explain why.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-ee42ff8d2326e213', 'subject-card-fd50ab2928f76c05', 'feynmanChecklist', 'Feynman mastery checklist', 0, 'text', 'Can you explain each model in one clear sentence?', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-ede7fe480efde4b6', 'subject-card-fd50ab2928f76c05', 'feynmanChecklist', 'Feynman mastery checklist', 1, 'text', 'Can you draw each model and label parts?', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-269420ba5a7517b8', 'subject-card-fd50ab2928f76c05', 'feynmanChecklist', 'Feynman mastery checklist', 2, 'text', 'Can you say which experiment led to each new model and why?', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-20ab879c83d28c29', 'subject-card-fd50ab2928f76c05', 'applications', 'Real-world applications', 0, 'text', 'Understanding atomic models helps explain chemical behavior, light spectra, and how instruments (like electron microscopes) work.', NULL, NULL);
